// Edite só este arquivo com seus dados reais
const CONFIG = {
  // Número com DDD e código do país, só números. Exemplo: 5511987654321
  whatsapp: "5511999999999",

  mensagemConfirmar:
    "Oi Victória! Confirmo presença na sua festa de 15 anos! 🎉",

  mensagemEndereco:
    "Oi Victória! Pode me passar o endereço da festa? 📍",

  mensagemDuvida: "Oi Victória! Tenho uma dúvida sobre a festa.",

  // Se tiver link do Google Maps, cole aqui. Senão deixa vazio.
  linkMaps: "",

  musica: "assets/musica.mp3",
};

function linkWhatsApp(mensagem) {
  const texto = encodeURIComponent(mensagem);
  return `https://wa.me/${CONFIG.whatsapp}?text=${texto}`;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body {
  height: 100%;
  background: #2a0a45;
  font-family: Georgia, "Times New Roman", serif;
}

body {
  display: flex;
  justify-content: center;
  align-items: flex-start;
  min-height: 100dvh;
}

.app {
  width: 100%;
  max-width: 430px;
  min-height: 100dvh;
  position: relative;
  background: #2a0a45;
}

.tela {
  display: none;
  width: 100%;
}

.tela.ativa {
  display: block;
}

.convite-img {
  display: block;
  width: 100%;
  height: auto;
  user-select: none;
  -webkit-user-drag: none;
}

.img-wrap {
  position: relative;
  width: 100%;
  line-height: 0;
}

.hotspot {
  position: absolute;
  border: none;
  background: transparent;
  cursor: pointer;
  padding: 0;
  border-radius: 50%;
  -webkit-tap-highlight-color: transparent;
}

.hotspot:focus-visible {
  outline: 2px solid rgba(255, 255, 255, 0.8);
  outline-offset: 2px;
}

/* Posições calibradas para capa 1240×1748 */
.hotspot-local {
  left: 8%;
  top: 68%;
  width: 28%;
  height: 14%;
}

.hotspot-presentes {
  left: 64%;
  top: 65%;
  width: 28%;
  height: 14%;
}

.hotspot-informacoes {
  left: 32%;
  top: 82%;
  width: 36%;
  height: 12%;
}

.hotspot-duvida {
  left: 10%;
  top: 90%;
  width: 80%;
  height: 8%;
  border-radius: 8px;
}

.btn-voltar {
  position: fixed;
  top: 12px;
  left: 12px;
  z-index: 20;
  border: 1px solid rgba(255, 255, 255, 0.5);
  background: rgba(42, 10, 69, 0.85);
  color: #fff;
  padding: 8px 14px;
  border-radius: 999px;
  font-size: 14px;
  cursor: pointer;
  backdrop-filter: blur(4px);
}

.btn-musica {
  position: fixed;
  top: 12px;
  right: 12px;
  z-index: 20;
  width: 44px;
  height: 44px;
  border: 1px solid rgba(255, 255, 255, 0.5);
  background: rgba(42, 10, 69, 0.85);
  color: #fff;
  border-radius: 50%;
  font-size: 18px;
  cursor: pointer;
  backdrop-filter: blur(4px);
}

.overlay-musica {
  position: fixed;
  inset: 0;
  z-index: 30;
  display: none;
  align-items: center;
  justify-content: center;
  padding: 24px;
  background: rgba(20, 5, 35, 0.72);
}

.overlay-musica.visivel {
  display: flex;
}

.overlay-musica button {
  border: none;
  background: #fff;
  color: #2a0a45;
  padding: 14px 22px;
  border-radius: 999px;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
}

.btn-zap {
  position: fixed;
  bottom: 18px;
  right: 18px;
  z-index: 20;
  width: 56px;
  height: 56px;
  border: none;
  border-radius: 50%;
  background: #25d366;
  color: #fff;
  font-size: 28px;
  line-height: 1;
  cursor: pointer;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.35);
  text-decoration: none;
  display: flex;
  align-items: center;
  justify-content: center;
}

const telas = {
  capa: document.getElementById("tela-capa"),
  presentes: document.getElementById("tela-presentes"),
  informacoes: document.getElementById("tela-informacoes"),
};

const audio = document.getElementById("musica");
const btnMusica = document.getElementById("btn-musica");
const overlayMusica = document.getElementById("overlay-musica");
const btnIniciar = document.getElementById("btn-iniciar");

let musicaLigada = false;

function mostrarTela(nome) {
  Object.values(telas).forEach((tela) => tela.classList.remove("ativa"));
  telas[nome].classList.add("ativa");
  window.scrollTo(0, 0);
}

function atualizarIconeMusica() {
  btnMusica.textContent = musicaLigada ? "🔊" : "🔇";
  btnMusica.setAttribute(
    "aria-label",
    musicaLigada ? "Pausar música" : "Tocar música"
  );
}

async function ligarMusica() {
  if (!audio.src) return;

  try {
    audio.volume = 0.45;
    await audio.play();
    musicaLigada = true;
  } catch {
    musicaLigada = false;
  }

  atualizarIconeMusica();
}

function pausarMusica() {
  audio.pause();
  musicaLigada = false;
  atualizarIconeMusica();
}

async function alternarMusica() {
  if (musicaLigada) {
    pausarMusica();
    return;
  }

  await ligarMusica();
}

function abrirLocal() {
  if (CONFIG.linkMaps) {
    window.open(CONFIG.linkMaps, "_blank", "noopener");
    return;
  }

  window.open(linkWhatsApp(CONFIG.mensagemEndereco), "_blank", "noopener");
}

function iniciarConvite() {
  overlayMusica.classList.remove("visivel");
  ligarMusica();
}

document.getElementById("btn-local").addEventListener("click", abrirLocal);

document.getElementById("btn-presentes").addEventListener("click", () => {
  mostrarTela("presentes");
});

document.getElementById("btn-informacoes").addEventListener("click", () => {
  mostrarTela("informacoes");
});

document.getElementById("btn-duvida").addEventListener("click", () => {
  window.open(linkWhatsApp(CONFIG.mensagemDuvida), "_blank", "noopener");
});

document.querySelectorAll("[data-voltar]").forEach((btn) => {
  btn.addEventListener("click", () => mostrarTela("capa"));
});

document.getElementById("btn-confirmar").href = linkWhatsApp(
  CONFIG.mensagemConfirmar
);

btnMusica.addEventListener("click", alternarMusica);
btnIniciar.addEventListener("click", iniciarConvite);

audio.addEventListener("ended", () => {
  audio.currentTime = 0;
  audio.play().catch(() => {});
});

if (CONFIG.musica) {
  audio.src = CONFIG.musica;
  overlayMusica.classList.add("visivel");
} else {
  overlayMusica.classList.remove("visivel");
}

atualizarIconeMusica();
mostrarTela("capa");

